    trie := buildTrie(words)
    visited := make([][]bool, len(board))
    for i := range visited {
        visited[i] = make([]bool, len(board[0]))
    }

    for i := 0; i < len(board); i++ {
        for j := 0; j < len(board[0]); j++ {
            dfs(board, i, j, trie, "", &result, visited)
        }
    }
    return result
}

func dfs(board [][]byte, i, j int, node *TrieNode, path string, result *[]string, visited [][]bool) {
    if node.isEnd {
        *result = append(*result, path)
        node.isEnd = false // Avoid duplicates
    }
    if i < 0 || i >= len(board) || j < 0 || j >= len(board[0]) || visited[i][j] {
        return
    }
    char := board[i][j]
    nextNode := node.children[char]
    if nextNode == nil {
        return
    }
    visited[i][j] = true
    dfs(board, i+1, j, nextNode, path+string(char), result, visited)
    dfs(board, i-1, j, nextNode, path+string(char), result, visited)
    dfs(board, i, j+1, nextNode, path+string(char), result, visited)
    dfs(board, i, j-1, nextNode, path+string(char), result, visited)
    visited[i][j] = false
}

