using System;
using System.Collections.Generic;

public class Solution {
    public List<string> wordSearchIi(char[][] board, string[] words) {
        HashSet<string> result = new HashSet<string>();
        TrieNode root = BuildTrie(words);

        for (int i = 0; i < board.Length; i++) {
            for (int j = 0; j < board[0].Length; j++) {
                DFS(board, i, j, root, "", result);
            }
        }

        return new List<string>(result);
    }

    private void DFS(char[][] board, int i, int j, TrieNode node, string path, HashSet<string> result) {
        if (node.IsEnd) {
            result.Add(path);
        }

        if (i < 0 || i >= board.Length || j < 0 || j >= board[0].Length || board[i][j] == '#') {
            return;
        }

        char temp = board[i][j];
        node = node.Children[temp - 'a'];
        if (node == null) return;

        board[i][j] = '#'; // mark as visited

        DFS(board, i + 1, j, node, path + temp, result);
        DFS(board, i - 1, j, node, path + temp, result);
        DFS(board, i, j + 1, node, path + temp, result);
        DFS(board, i, j - 1, node, path + temp, result);

        board[i][j] = temp; // unmark
    }

    private TrieNode BuildTrie(string[] words) {
        TrieNode root = new TrieNode();
        foreach (string word in words) {
            TrieNode node = root;
            foreach (char c in word) {
                if (node.Children[c - 'a'] == null) {
                    node.Children[c - 'a'] = new TrieNode();
                }
                node = node.Children[c - 'a'];
            }
            node.IsEnd = true;
        }
        return root;
    }
}

