package main

import (
    "fmt"
)

type TrieNode struct {
    children map[rune]*TrieNode
    isEnd    bool
}

type Trie struct {
    root *TrieNode
}

func NewTrie() *Trie {
    return &Trie{root: &TrieNode{children: make(map[rune]*TrieNode)}}
}

func (t *Trie) Insert(word string) {
    node := t.root
    for _, ch := range word {
        if _, exists := node.children[ch]; !exists {
            node.children[ch] = &TrieNode{children: make(map[rune]*TrieNode)}
        }
        node = node.children[ch]
    }
    node.isEnd = true
}

func (t *Trie) Search(word string) bool {
    node := t.root
    for _, ch := range word {
        if _, exists := node.children[ch]; !exists {
            return false
        }
        node = node.children[ch]
    }
    return node.isEnd
}

func (t *Trie) StartsWith(prefix string) bool {
    node := t.root
    for _, ch := range prefix {
        if _, exists := node.children[ch]; !exists {
            return false
        }
        node = node.children[ch]
    }
    return true
}

func wordSearchIi(board [][]rune, words []string) []string {
    trie := NewTrie()
    for _, word := range words {
        trie.Insert(word)
    }

    result := make(map[string]struct{})
    rows, cols := len(board), len(board[0])
    var dfs func(x, y int, node *TrieNode, path string)

    dfs = func(x, y int, node *TrieNode, path string) {
        if node.isEnd {
            result[path] = struct{}{}
        }
        if x < 0 || x >= rows || y < 0 || y >= cols || board[x][y] == '#' {
            return
        }
        ch := board[x][y]
        if _, exists := node.children[ch]; !exists {
            return
        }
        board[x][y] = '#' // mark as visited
        dfs(x+1, y, node.children[ch], path+string(ch))
        dfs(x-1, y, node.children[ch], path+string(ch))
        dfs(x, y+1, node.children[ch], path+string(ch))
        dfs(x, y-1, node.children[ch], path+string(ch))
