public class Solution {
    private class TrieNode {
        public Dictionary<char, TrieNode> Children = new Dictionary<char, TrieNode>();
        public bool IsEndOfWord = false;
    }

    private TrieNode root;
    private HashSet<string> result;
    private char[][] board;
    private int rows, cols;

    public List<string> wordSearchIi(char[][] data) {
        root = new TrieNode();
        result = new HashSet<string>();
        board = data;
        rows = board.Length;
        cols = board[0].Length;

        // Example words to search for, this should be passed or defined elsewhere
        string[] words = { "oath", "pea", "eat", "rain" };
        BuildTrie(words);

        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                DFS(i, j, root, "");
            }
        }

        return new List<string>(result);
    }

    private void BuildTrie(string[] words) {
        foreach (var word in words) {
            var node = root;
            foreach (var ch in word) {
                if (!node.Children.ContainsKey(ch)) {
                    node.Children[ch] = new TrieNode();
                }
                node = node.Children[ch];
            }
            node.IsEndOfWord = true;
        }
    }

    private void DFS(int i, int j, TrieNode node, string currentWord) {
        if (node.IsEndOfWord) {
            result.Add(currentWord);
            node.IsEndOfWord = false; // Avoid duplicate entries
        }

        if (i < 0 || i >= rows || j < 0 || j >= cols || board[i][j] == '#') {
            return;
        }

        char ch = board[i][j];
        if (!node.Children.ContainsKey(ch)) {
            return;
        }

        currentWord += ch;
        board[i][j] = '#'; // Mark as visited

        DFS(i + 1, j, node.Children[ch], currentWord);
        DFS(i - 1, j, node.Children[ch], currentWord);
        DFS(i, j + 1, node.Children[ch], currentWord);
        DFS(i, j - 1, node.Children[ch], currentWord);

        board[i][j] = ch; // Unmark
    }
}
